PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?bronze ?birthDate WHERE {
  ?event wdt:P641 wd:Q543 ;
         wdt:P361 wd:Q28508 ;
         wdt:P1346 wd:Q4255935 ;
         wdt:P1344 ?bronze .
  ?bronze wdt:P569 ?birthDate .
}
LIMIT 1

