PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?bronze ?birthDate WHERE {
  ?event wdt:P641 wd:Q543 ;
         wdt:P361 wd:Q28508 ;
         p:P1346 ?goldStatement ;
         p:P1346 ?bronzeStatement .

  ?goldStatement ps:P1346 wd:Q4255935 ;
                 pq:P135 ?goldRank .
  FILTER (?goldRank = 1)

  ?bronzeStatement ps:P1346 ?bronze ;
                 pq:P135 ?bronzeRank .
  FILTER (?bronzeRank = 3)

  ?bronze wdt:P569 ?birthDate .
}
LIMIT 1
